import java.util.ArrayList;
import java.util.LinkedList;
import java.util.Queue;

public class GraphTraversals {
    // Process: Breadth-First Search (BFS)
    public static void bfs(int start, ArrayList<ArrayList<Integer>> adj, boolean[] visited) {
        // Storage: Queue and visited tracker
        Queue<Integer> queue = new LinkedList<>();

        visited[start] = true;
        queue.add(start); // Input source

        while (!queue.isEmpty()) {
            int node = queue.poll();
            System.out.print(node + " "); // Output

            // Process: Queue adjacent unvisited nodes
            for (int neighbor : adj.get(node)) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true;
                    queue.add(neighbor);
                }
            } 
        }
    }
}

