import java.util.ArrayList;
import java.util.PriorityQueue;

public class BestFirstSearch {
    public static class Node implements Comparable<Node> {
        int vertex, cost;
        Node(int v, int c) { vertex = v; cost = c; }
        public int compareTo(Node other) { return this.cost - other.cost; }
    }

    public static void search(int start, int target, ArrayList<ArrayList<Node>> adj, int V) {
        // Input: start, target, graph adjacency list with costs

        // Storage: PriorityQueue and visited tracker
        PriorityQueue<Node> pq = new PriorityQueue<>();
        boolean[] visited = new boolean[V];

        pq.add(new Node(start, 0));
        visited[start] = true;

        // Process: Informed greedy search
        while (!pq.isEmpty()) {
            Node u = pq.poll(); // Storage: node with minimum cost
            System.out.print(u.vertex + " "); // Output

            if (u.vertex == target) break; // Goal found

            for (Node neighbor : adj.get(u.vertex)) {
                if (!visited[neighbor.vertex]) {
                    visited[neighbor.vertex] = true;
                    pq.add(new Node(neighbor.vertex, neighbor.cost));
                }
            }
        }
    }
}

