import java.util.ArrayList;
import java.util.LinkedList;
import java.util.Queue;

public class GraphBFSTraversal {
    public static ArrayList<Integer> bfsOfGraph(int V, ArrayList<ArrayList<Integer>> adj) {
        // Input: Vertices count V and adjacency list adj
        ArrayList<Integer> bfsResult = new ArrayList<>(); // Storage
        boolean[] visited = new boolean[V];              // Storage

        Queue<Integer> q = new LinkedList<>(); // Storage
        q.add(0);
        visited[0] = true;

        // Process: BFS queue logic
        while (!q.isEmpty()) {
            int node = q.poll(); // Storage
            bfsResult.add(node);

            for (int neighbor : adj.get(node)) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true;
                    q.add(neighbor);
                }
            }
        }
        // Output: Return traversal path list
        return bfsResult;
    }
}

