import java.util.ArrayList;

public class DisconnectedDFS {
    public static void dfs(int V, ArrayList<ArrayList<Integer>> adj) {
        // Input: Vertices V and Adjacency List adj

        // Storage: Visited tracker
        boolean[] visited = new boolean[V];

        // Process: Loop all vertices to handle disconnected components
        for (int i = 0; i < V; i++) {
            if (!visited[i]) {
                dfsHelper(i, adj, visited);
            }
        }
    }

    private static void dfsHelper(int u, ArrayList<ArrayList<Integer>> adj, boolean[] visited) {
        visited[u] = true;
        System.out.print(u + " "); // Output

        for (int v : adj.get(u)) {
            if (!visited[v]) {
                dfsHelper(v, adj, visited); // Process recursion
            }
        }
    }
}

import java.util.Arrays;

public class BellmanFord {
    public static boolean hasNegativeCycle(int V, int[][] edges) {
        // Input: V vertices and an edge list {src, dest, weight}
        int[] dist = new int[V];   // Storage: distance estimates
        Arrays.fill(dist, 0);      // 0 => detect a cycle reachable from any vertex

        // Process: relax every edge V-1 times
        for (int i = 1; i < V; i++) {
            for (int[] e : edges) {
                if (dist[e[0]] + e[2] < dist[e[1]]) {
                    dist[e[1]] = dist[e[0]] + e[2];
                }
            }
        }

        // Process: one extra pass - any relaxation means a negative cycle
        for (int[] e : edges) {
            if (dist[e[0]] + e[2] < dist[e[1]]) {
                return true; // Output: negative cycle found
            }
        }
        return false; // Output: no negative cycle
    }
}
